class TreeNode:
    def __init__(self, value=0, left=None, right=None):
        self.value = value
        self.left = left
        self.right = right

def build_tree():
    root = TreeNode(4)
    root.left = TreeNode(2, TreeNode(1))
    root.right = TreeNode(6, None, TreeNode(5, None, TreeNode(7)))
    return root

